/* serviceOrderCommon-sql-oracle.xml - selectServiceOrderHeaderCount */ SELECT COUNT(1) FROM ( SELECT A.OWKEY , MO.OWNM , A.SOHDKEY , A.ORDERTYPECD , A.CTKEY , MC.CTNM , A.ORDERISTDAY , A.CNFRMDAY , A.ORGORDERKEY , A.CLAIMNO , CASE WHEN A.RIRSNCD = '16' THEN 'Y' ELSE 'N' END AS NOTRTNDIV , A.RIRSNCD , A.WKSTATUS , (CASE WHEN (SELECT COUNT(*) FROM TORDER_INFO_HOLD X WHERE X.OWKEY = A.OWKEY AND X.COHDKEY = A.COHDKEY) > 0 THEN 'Y' ELSE 'N' END) AS HOLDYN , ( SELECT MIN(COM.COMDTNM) FROM TORDER_INFO_SO_WBLNO X INNER JOIN TORDER_MST_COM_DT COM ON X.OWKEY = A.OWKEY AND X.SOHDKEY = A.SOHDKEY AND X.OWKEY = COM.OWKEY AND X.DLVRYCORP = COM.COMDTKEY AND COM.COMHDKEY = 'DLVRY' ) AS DLVRYCORP , ( SELECT (CASE WHEN COUNT(DISTINCT X.WBLNO) > 1 THEN MIN(X.WBLNO) || ' 외 ' || (COUNT(DISTINCT X.WBLNO) - 1) || '건' ELSE MIN(X.WBLNO) END) AS WBLNO FROM TORDER_INFO_SO_WBLNO X WHERE X.OWKEY = A.OWKEY AND X.SOHDKEY = A.SOHDKEY ) AS WBLNO , COUNT(DISTINCT SD.ICKEY) AS ORDSKU , SUM(SD.EXPCTQTY) AS ORDEA , SUM(SD.EXPCTQTY * MI.SLPRC) AS ORDSLPRC , (CASE WHEN COALESCE(A.CNFRMDAY, '') = '' THEN COUNT(DISTINCT SD.ICKEY) ELSE 0 END) AS CNFSKU , (CASE WHEN COALESCE(A.CNFRMDAY, '') = '' THEN SUM(SD.EXPCTQTY) ELSE 0 END) AS CNFEA , (CASE WHEN COALESCE(A.CNFRMDAY, '') = '' THEN SUM(SD.EXPCTQTY * MI.SLPRC) ELSE 0 END) AS CNFSLPRC , COALESCE(( SELECT MIN(Y.WBLNO) FROM TORDER_INFO_SO_HD X INNER JOIN TORDER_INFO_SO_WBLNO Y ON X.OWKEY = A.OWKEY AND X.ORGORDERKEY = A.ORGORDERKEY AND X.OWKEY = Y.OWKEY AND X.SOHDKEY = Y.SOHDKEY WHERE 1 = 1 AND X.ORDERTYPECD = '100' ), '') AS EXCWBLNNO , A.CMT FROM TORDER_INFO_SO_HD A INNER JOIN TORDER_INFO_SO_DT SD ON A.OWKEY = SD.OWKEY AND A.SOHDKEY = SD.SOHDKEY INNER JOIN TORDER_MST_IC MI ON SD.OWKEY = MI.OWKEY AND SD.ICKEY = MI.ICKEY INNER JOIN TORDER_MST_OW MO ON A.OWKEY = MO.OWKEY INNER JOIN TORDER_MST_CT MC ON A.CTKEY = MC.CTKEY
INNER JOIN TORDER_INFO_SO_WBLNO SW ON A.OWKEY = SW.OWKEY AND A.SOHDKEY = SW.SOHDKEY AND SD.COHDKEY = SW.COHDKEY
WHERE #{SEARCH_CONDITION}
AND A.WKSTATUS != #{cancelYn}
AND A.ORDERTYPECD IN
#{orType}
AND SD.ICKEY IN
#{ickey}
AND SW.DLVRYCORP = #{isDlvrycorp}
AND SW.WBLNO = #{isRiwblno}
AND ( SELECT MIN(Y.WBLNO) FROM TORDER_INFO_SO_HD X INNER JOIN TORDER_INFO_SO_WBLNO Y ON X.OWKEY = A.OWKEY AND X.ORGORDERKEY = A.ORGORDERKEY AND X.OWKEY = Y.OWKEY AND X.SOHDKEY = Y.SOHDKEY WHERE 1 = 1 AND X.ORDERTYPECD = '100' ) = #{isExwblno}
GROUP BY A.OWKEY , A.CTKEY , A.ORDERISTDAY , A.CNFRMDAY , A.ORGORDERKEY , A.CLAIMNO , A.RIRSNCD , A.WKSTATUS , A.COHDKEY , A.SOHDKEY , MC.CTNM , A.CMT , A.OWKEY , MO.OWNM , A.SOHDKEY , A.ORDERTYPECD )

/* oms-order-serviceOrder-sql-oracle.xml - selectServiceOrderHeaderList */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , A.OWKEY , MO.OWNM , A.SOHDKEY , A.ORDERTYPECD , A.CTKEY , MC.CTNM , A.ORDERISTDAY , A.CNFRMDAY , A.ORGORDERKEY , A.CLAIMNO , CASE WHEN A.RIRSNCD = '16' THEN 'Y' ELSE 'N' END AS NOTRTNDIV , A.RIRSNCD , A.WKSTATUS , (CASE WHEN (SELECT COUNT(*) FROM TORDER_INFO_HOLD X WHERE X.OWKEY = A.OWKEY AND X.COHDKEY = A.COHDKEY) > 0 THEN 'Y' ELSE 'N' END) AS HOLDYN , (SELECT MIN(DLVRYCORP) FROM TORDER_INFO_SO_WBLNO X WHERE X.OWKEY = A.OWKEY AND X.SOHDKEY = A.SOHDKEY) AS DLVRYCORP , ( SELECT (CASE WHEN COUNT(DISTINCT X.WBLNO) > 1 THEN MIN(X.WBLNO) || ' 외 ' || (COUNT(DISTINCT X.WBLNO) - 1) || '건' ELSE MIN(X.WBLNO) END) AS WBLNO FROM TORDER_INFO_SO_WBLNO X WHERE X.OWKEY = A.OWKEY AND X.SOHDKEY = A.SOHDKEY ) AS WBLNO , COUNT(DISTINCT SD.ICKEY) AS ORDSKU , SUM(SD.EXPCTQTY) AS ORDEA , SUM(SD.EXPCTQTY * MI.SLPRC) AS ORDSLPRC , (CASE WHEN COALESCE(A.CNFRMDAY, '') = '' THEN COUNT(DISTINCT SD.ICKEY) ELSE 0 END) AS CNFSKU , (CASE WHEN COALESCE(A.CNFRMDAY, '') = '' THEN SUM(SD.EXPCTQTY) ELSE 0 END) AS CNFEA , (CASE WHEN COALESCE(A.CNFRMDAY, '') = '' THEN SUM(SD.EXPCTQTY * MI.SLPRC) ELSE 0 END) AS CNFSLPRC , COALESCE(( SELECT MIN(Y.WBLNO) FROM TORDER_INFO_SO_HD X INNER JOIN TORDER_INFO_SO_WBLNO Y ON X.OWKEY = A.OWKEY AND X.ORGORDERKEY = A.ORGORDERKEY AND X.OWKEY = Y.OWKEY AND X.SOHDKEY = Y.SOHDKEY WHERE 1 = 1 AND X.ORDERTYPECD = '100' ), '') AS EXCWBLNNO , A.CMT , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TORDER_INFO_SO_HD A INNER JOIN TORDER_INFO_SO_DT SD ON A.OWKEY = SD.OWKEY AND A.SOHDKEY = SD.SOHDKEY INNER JOIN TORDER_MST_IC MI ON SD.OWKEY = MI.OWKEY AND SD.ICKEY = MI.ICKEY INNER JOIN TORDER_MST_OW MO ON A.OWKEY = MO.OWKEY INNER JOIN TORDER_MST_CT MC ON A.CTKEY = MC.CTKEY
INNER JOIN TORDER_INFO_SO_WBLNO SW ON A.OWKEY = SW.OWKEY AND A.SOHDKEY = SW.SOHDKEY AND SD.COHDKEY = SW.COHDKEY
WHERE #{SEARCH_CONDITION}
AND A.WKSTATUS != #{cancelYn}
AND A.ORDERTYPECD IN
#{orType}
AND SD.ICKEY IN
#{ickey}
AND SW.DLVRYCORP = #{isDlvrycorp}
AND SW.WBLNO = #{isRiwblno}
AND ( SELECT MIN(Y.WBLNO) FROM TORDER_INFO_SO_HD X INNER JOIN TORDER_INFO_SO_WBLNO Y ON X.OWKEY = A.OWKEY AND X.ORGORDERKEY = A.ORGORDERKEY AND X.OWKEY = Y.OWKEY AND X.SOHDKEY = Y.SOHDKEY WHERE 1 = 1 AND X.ORDERTYPECD = '100' ) = #{isExwblno}
GROUP BY A.OWKEY , A.CTKEY , A.ORDERISTDAY , A.CNFRMDAY , A.ORGORDERKEY , A.CLAIMNO , A.RIRSNCD , A.WKSTATUS , A.COHDKEY , A.SOHDKEY , MC.CTNM , A.CMT , A.OWKEY , MO.OWNM , A.SOHDKEY , A.ORDERTYPECD , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY #{GRIDPAGING_ROWNUMTYPE_BOTTOM}

