/* serviceOrderCommon-sql-oracle.xml - insertInboundOrderEtcHeaderList */
INSERT INTO TORDER_INFO_SO_HD (
      OWKEY
    , SO_HDKEY
    , SO_GR_HDKEY
    , SO_GR_DTKEY
    , OR_HDDATE
    , OR_DATE
    , OR_TYPE_CD
    , WKSTATUS
    , CTKEY
    , DELIVERY_KEY
    , STORE_KEY
    , BILLKEY
    , PAYERKEY
    , ACKEY
    , LOGGRPCD
    , EXTERNORDERKEY
    , TO_CTKEY
    , OR_HDDATE_TO
    , ICGRTYPE
    , ICGRKEY
    , PO_TYPE
    , REFERENCEKEY
    , SALESPERSON_ID
    , DELIVERY_PERSON_ID
    , EDI_YN
    , COMMENTS
    , OR_CANCEL_YN
    , OR_CANCEL_DATE
    , OR_CANCEL_USERID
    , OR_SEND_YN
    , OR_SEND_DATE
    , OR_SEND_USERID
    , DELIVERY_ADDRID
    , ORDER_ERROR_CD
    , ORDER_ERROR_COMMENTS
    , INSERTDATE
    , INSERTURKEY
    , UPDATEDATE
    , UPDATEURKEY
    , CUSTOMERORDERKEY
    , EXTORDERTYPECD
    , ORREASONCD
) VALUES (
          #{owkey}
        , #{soHdkey}
        , #{soGrHdkey}
        , #{soGrDtkey}
        , #{orHddate}
        , #{orDate}
        , #{orTypeCd}
        , #{wkstatus}
        , #{ctkey}
        , #{deliveryKey}
        , #{storeKey}
        , #{billkey}
        , #{payerkey}
        , #{ackey}
        , #{loggrpcd}
        , #{externorderkey}
        , #{toCtkey}
        , #{orHddateTo}
        , #{icgrtype}
        , #{icgrkey}
        , #{poType}
        , #{referencekey}
        , #{salespersonId}
        , #{deliveryPersonId}
        , #{ediYn}
        , #{comments}
        , COALESCE(#{orCancelYn}, 'N')
        , #{orCancelDate}
        , #{orCancelUserid}
        , COALESCE(#{orSendYn}, 'N')
        , #{orSendDate}
        , #{orSendUserid}
        , #{deliveryAddrid}
        , #{orderErorrCd}
        , #{orderErrorComments}
        , #{sysdate}
        , #{surkey}
        , #{sysdate}
        , #{surkey}
        , #{customerorderkey}
        , #{extordertypecd}
        , #{orreasoncd}
)

